// Forward substitution: lower-triangular A, produces x
for (int i = 0; i < n; i++) {
    double s = b[i];
    for (int j = 0; j < i; j++) {          // subtract known terms
        s -= A[i][j] * x[j];
    }
    x[i] = s / A[i][i];                    // divide by diagonal pivot
}

// Gaussian elimination (no pivoting; see next step for why that's dangerous)
for (int r = 0; r < n - 1; r++) {
    // Stage r: zero column r below row r
    for (int i = r + 1; i < n; i++) {
        double f = -A[i][r] / A[r][r];   // multiplier; divides by pivot
        for (int j = r + 1; j < n; j++) {
            A[i][j] += f * A[r][j];       // update row i
        }
        A[i][r] = 0.0;                    // enforce the zero (was ~eps)
        b[i]    += f * b[r];              // update RHS the same way
    }
}
// Now A is upper-triangular; solve by back substitution.
back_substitute(A, b, x);
